const express = require('express');
const app = express();
const PORT = 3000;


app.get('/', (req, res) => {
  try {
    res.status(200).json({ message: 'A szerver működik!' });
  } catch (err) {
    res.status(500).json({ error: 'Szerverhiba', details: err.message });
  }
});

// GET /health - szerver futási ideje
app.get('/health', (req, res) => {
  try {
    res.status(200).json({ uptime: process.uptime() });
  } catch (err) {
    res.status(500).json({ error: 'Szerverhiba', details: err.message });
  }
});

// GET /info - statikus információk
app.get('/info', (req, res) => {
  try {
    const info = {
      app: 'PRF gyakorlat',
      version: 'v1.0.0',
      author: 'Jánki Z.'
    };
    const queries = req.query;
    res.status(200).json({ ...info, queries });
  } catch (err) {
    res.status(500).json({ error: 'Szerverhiba', details: err.message });
  }
});



// Globális hibakezelő middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Szerverhiba', details: err.message });
});

app.listen(PORT, () => {
  console.log(`A szerver fut a ${PORT}-es porton.`);
});

