const { Observable } = require('rxjs');

function delayObservable(ms) {
  return new Observable((subscriber) => {
    setTimeout(() => {
      subscriber.next();
      subscriber.complete();
    }, ms);
  });
}

// GET /slow-observable - Observable + async/await
